import{_ as t,c as o,o as s,a5 as r}from"./chunks/framework.CgT1UzWm.js";const g=JSON.parse('{"title":"Support NpgsqlRest","description":"NpgsqlRest is free, MIT-licensed, and built by one person out of passion. If it saves you time or money, here is how to support its development.","frontmatter":{"title":"Support NpgsqlRest","description":"NpgsqlRest is free, MIT-licensed, and built by one person out of passion. If it saves you time or money, here is how to support its development.","head":[["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/support.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/support.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"Support NpgsqlRest"}],["meta",{"property":"og:description","content":"NpgsqlRest is free, MIT-licensed, and built by one person out of passion. If it saves you time or money, here is how to support its development."}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Support NpgsqlRest"}],["meta",{"name":"twitter:description","content":"NpgsqlRest is free, MIT-licensed, and built by one person out of passion. If it saves you time or money, here is how to support its development."}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"support.md","filePath":"support.md","lastUpdated":1782480183000}'),a={name:"support.md"};function n(i,e,p,l,h,u){return s(),o("div",null,e[0]||(e[0]=[r('<h1 id="support-npgsqlrest-❤️" tabindex="-1">Support NpgsqlRest ❤️ <a class="header-anchor" href="#support-npgsqlrest-❤️" aria-label="Permalink to &quot;Support NpgsqlRest ❤️&quot;">​</a></h1><h2 id="a-note-from-the-author" tabindex="-1">A Note From the Author <a class="header-anchor" href="#a-note-from-the-author" aria-label="Permalink to &quot;A Note From the Author&quot;">​</a></h2><p>Hi, I&#39;m <a href="https://www.linkedin.com/in/vb-software/" target="_blank" rel="noreferrer">Vedran</a>, and NpgsqlRest is my passion project.</p><p>It is much more than a project, though. It&#39;s an entire philosophy — and one completely at odds with what passes for mainstream, modern development. The database <strong>is</strong> the application. PostgreSQL <strong>is</strong> the tier — not infrastructure, not just a data store hidden behind layers of ORMs, mappers, and &quot;clean&quot; architecture rebuilding what it already does better.</p><p>NpgsqlRest is the materialized compilation of everything I have been arguing for years. And in the process, it can save you countless working hours, bugs, and tokens.</p><p>I have been building it for years — nights, weekends, and every spare hour — with no company behind it and no compensation of any kind. I&#39;ve risked a lot professionally to build it. And I built it for free: there is no paid tier, no telemetry, and no enterprise edition waiting behind a paywall. Everything is MIT-licensed, for any use, commercial included. And it will stay that way.</p><p>You don&#39;t have to agree with me. If you don&#39;t — please, <a href="https://github.com/NpgsqlRest/NpgsqlRest/discussions" target="_blank" rel="noreferrer">bring some valid arguments</a>, I&#39;ll engage. But if you do, and you like this project, consider supporting my work in whatever form suits you. I&#39;d very much appreciate it.</p><h2 id="what-sponsorship-funds" tabindex="-1">What Sponsorship Funds <a class="header-anchor" href="#what-sponsorship-funds" aria-label="Permalink to &quot;What Sponsorship Funds&quot;">​</a></h2><ul><li><strong>Development</strong> — new features, bug fixes, and a steady release cadence (50+ releases in the 3.x line alone).</li><li><strong>Support</strong> — answering issues and discussions, and helping people get unstuck.</li><li><strong>Quality</strong> — testing and benchmarking across Windows, Linux, and macOS.</li><li><strong>Documentation</strong> — the guides, references, examples, and blog posts on this site.</li></ul><h2 id="how-to-sponsor" tabindex="-1">How to Sponsor <a class="header-anchor" href="#how-to-sponsor" aria-label="Permalink to &quot;How to Sponsor&quot;">​</a></h2><p>The primary way to support NpgsqlRest is <strong>GitHub Sponsors</strong> — it works for both individuals and organizations, and 100% of your sponsorship goes to the project:</p><div class="support-cta"><a href="https://github.com/sponsors/NpgsqlRest" target="_blank"><svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 16 16" fill="currentColor"><path d="M7.655 14.916v-.001h-.002l-.006-.003-.018-.01a22.066 22.066 0 0 1-3.744-2.584C2.045 10.731 0 8.35 0 5.5 0 2.836 2.086 1 4.25 1 5.797 1 7.153 1.802 8 3.02 8.847 1.802 10.203 1 11.75 1 13.914 1 16 2.836 16 5.5c0 2.85-2.045 5.231-3.885 6.818a22.066 22.066 0 0 1-3.744 2.584l-.018.01-.006.003h-.002a.75.75 0 0 1-.69 0Z"></path></svg> Sponsor on GitHub </a></div><p>Prefer another platform? These work too:</p><ul><li><a href="https://patreon.com/vbconsulting" target="_blank" rel="noreferrer">Patreon</a></li><li><a href="https://buymeacoffee.com/vbilopavu" target="_blank" rel="noreferrer">Buy Me a Coffee</a></li></ul><h2 id="not-in-a-position-to-sponsor" tabindex="-1">Not in a Position to Sponsor? <a class="header-anchor" href="#not-in-a-position-to-sponsor" aria-label="Permalink to &quot;Not in a Position to Sponsor?&quot;">​</a></h2><p>No problem — these things help the project just as much:</p><ul><li>⭐ <a href="https://github.com/NpgsqlRest/NpgsqlRest" target="_blank" rel="noreferrer">Star the repository</a> — visibility is how open source grows.</li><li>🐛 <a href="https://github.com/NpgsqlRest/NpgsqlRest/issues" target="_blank" rel="noreferrer">Report issues</a> — a good bug report is a contribution.</li><li>📣 Write or talk about NpgsqlRest — a blog post, a team demo, or a mention where developers gather.</li><li>💬 Share your experience — <a href="https://github.com/NpgsqlRest/NpgsqlRest/discussions" target="_blank" rel="noreferrer">a comment, a question, or a case study</a> helps others decide.</li></ul><p>Thank you for using NpgsqlRest.</p>',18)]))}const c=t(a,[["render",n]]);export{g as __pageData,c as default};
